// ─────────────────────────────────────────────────────────────
// NODE 3 — GROUP FILES BY PRODUCT
// The previous node returns one item per file (15 items per
// product × 16 products = 240 items). This node groups them
// back into 16 items, one per product, each containing all
// 15 file IDs mapped to their document slot.
// ─────────────────────────────────────────────────────────────

// Collect all items from the List 15 Documents node
const allItems = $input.all();

// Each item has: { id (file id), name (e.g. '=HiSociety - Screenplay'), parent folder name }
// We need the product name — extract from filename before the ' - '
// File format: '={ProductName} - {DocumentType}'

// Document type → slot key mapping (matches exact suffix after ' - ')
const TYPE_TO_SLOT = {
  'User Guide':             'userGuide',
  'One Pager':              'onePager',
  'Storyboard':             'storyboard',
  'Screenplay':             'screenplay',
  'Marketing Script':       'marketingScript',
  'Industry Feature List':  'industryFeatureList',
  'Elevator Pitch':         'elevatorPitch',
  'Communication Strategy': 'communicationStrategy',
  'Research Report':        'researchReport',
  'Product Description':    'productDescription',
  'Product Overview':       'productOverview',
  'Video Summary':          'videoSummary',
  'Gemini Analysis':        'geminiAnalysis',
  'AI Transcript':          'aiTranscript',
  'Original Transcript':    'originalTranscript',
};

// Group by product name
const productMap = {};

for (const item of allItems) {
  const fileName = item.json.name || '';
  const fileId   = item.json.id   || '';

  // Strip leading '=' and split on ' - '
  // e.g. '=HiSociety - Original Transcript' → ['HiSociety', 'Original Transcript']
  const stripped = fileName.startsWith('=') ? fileName.slice(1) : fileName;
  const dashIdx  = stripped.indexOf(' - ');
  if (dashIdx === -1) {
    console.warn(`Skipping unrecognised filename format: ${fileName}`);
    continue;
  }

  const productName = stripped.substring(0, dashIdx).trim();
  const docType     = stripped.substring(dashIdx + 3).trim();
  const slot        = TYPE_TO_SLOT[docType];

  if (!slot) {
    console.warn(`No slot mapping for doc type: '${docType}' (file: ${fileName})`);
    continue;
  }

  if (!productMap[productName]) {
    productMap[productName] = { productName, fileIds: {} };
  }
  productMap[productName].fileIds[slot] = fileId;
}

const products = Object.values(productMap);
console.log(`Grouped ${allItems.length} files into ${products.length} products:`, products.map(p => `${p.productName} (${Object.keys(p.fileIds).length} docs)`));

if (products.length === 0) {
  throw new Error('No products grouped — check file naming format matches: =ProductName - Document Type');
}

return products.map(p => ({ json: p }));

const data = $input.first().json;
