  regionKeys.forEach(({ key, label, color }) => {
    const regionData = industry.regions?.[key] || {};
    html += `<div class="region-header" style="background:${color};">${label} — ${name}</div>`;
    sectionKeys.forEach(({ key: sk, label: sl }) => {
      const content = regionData[sk] || 'Not available.';
      html += `
      <div class="section-label" style="color:${color}; border-color:${color};">${sl}</div>
      <div class="section-content">${content.replace(/\n/g, '<br>')}</div>`;
    });
  });
});

html += `</body></html>`;

const base64 = Buffer.from(html).toString('base64');
const safe = productName.replace(/[^a-zA-Z0-9_\- ]/g, '_').replace(/\s+/g, '_').substring(0, 50);
const date = new Date().toISOString().slice(0, 10);
const fileName = `${safe}_Industry_Intelligence_${date}.html`;

return [{
  json: { productName, fileName },
  binary: {
    data: {
      data: base64,
      mimeType: 'text/html',
      fileName: fileName,
      fileExtension: 'html',
    },
  },
}];

const results = $input.all().map(i => i.json);
console.log(`=== Run complete: ${results.length} products processed ===`);
results.forEach(r => console.log(`  ✓ ${r.name || r.productName}`));
return [{ json: { status: 'complete', processed: results.length, files: results.map(r => r.name || r.productName) } }];

const { productName, fileIds } = $input.first().json;

const SLOT_MAP = {
  originalTranscript:    fileIds.originalTranscript    || '',
  aiTranscript:          fileIds.aiTranscript          || '',
  geminiAnalysis:        fileIds.geminiAnalysis        || '',
  videoSummary:          fileIds.videoSummary          || '',
  productOverview:       fileIds.productOverview       || '',
  productDescription:    fileIds.productDescription    || '',
  userGuide:             fileIds.userGuide             || '',
  elevatorPitch:         fileIds.elevatorPitch         || '',
  onePager:              fileIds.onePager              || '',
  researchReport:        fileIds.researchReport        || '',
  industryFeatureList:   fileIds.industryFeatureList   || '',
  marketingScript:       fileIds.marketingScript       || '',
  communicationStrategy: fileIds.communicationStrategy || '',
  storyboard:            fileIds.storyboard            || '',
  screenplay:            fileIds.screenplay            || '',
};

// Output one item per file — HTTP Request node will process each
return Object.entries(SLOT_MAP)
  .filter(([slot, id]) => id !== '')
  .map(([slot, id]) => ({
    json: { productName, slot, fileId: id }
  }));

const items = $input.all();
const productName = items[0].json.productName;

const docs = {};
for (const item of items) {
  const slot = item.json.slot;
  const text = item.json.documentText || item.json.data || item.json.body || '';
  docs[slot] = typeof text === 'string' ? text.trim() : JSON.stringify(text);
}

console.log(`[${productName}] Grouped ${Object.keys(docs).length} docs`);

return [{ json: { productName, docs, filledSlots: Object.keys(docs).length } }];

const input = $input.first().json;

// Handle HTTP Request node output (Groq API response)
const content = input.choices?.[0]?.message?.content
  || input.message?.content
  || input.text
  || input.content
  || '';

// If input is already parsed JSON (no content field), just pass it through
if (!content) {
  return [{ json: input }];
}

let clean = content
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(clean);
} catch (e) {
  throw new Error(`JSON parse failed: ${e.message}\n\nPreview: ${clean.slice(0, 300)}`);
}

return [{ json: parsed }];

